PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE transactions (id INTEGER PRIMARY KEY, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP, user_id TEXT, amount REAL, type TEXT, status TEXT);
CREATE TABLE marketplace (id INTEGER PRIMARY KEY, name TEXT, price REAL, barcode TEXT, stock_quantity INTEGER, village TEXT, category TEXT, description TEXT);
CREATE TABLE categories (
        id INTEGER PRIMARY KEY,
        name TEXT UNIQUE,
        description TEXT
    );
ANALYZE sqlite_schema;
COMMIT;
